// ===== WORKER 1: public-gateway.js =====
// This is the public-facing worker that accepts user requests

export default {
  async fetch(request, env) {
    const url = new URL(request.url);
    const path = url.pathname;

    try {
      if (path.startsWith('/api/users')) {
        return await env.USER_SERVICE.fetch(request);
      } else if (path.startsWith('/api/products')) {
        return await env.PRODUCT_SERVICE.fetch(request);
      } else if (path.startsWith('/api/orders')) {
        return await env.ORDER_SERVICE.fetch(request);
      } else if (path.startsWith('/api/analytics')) {
        return await env.ANALYTICS_SERVICE.fetch(request);
      } else if (path === '/health') {
        const healthChecks = await Promise.all([
          checkServiceHealth(env.USER_SERVICE, 'user-service'),
          checkServiceHealth(env.PRODUCT_SERVICE, 'product-service'),
          checkServiceHealth(env.ORDER_SERVICE, 'order-service'),
          checkServiceHealth(env.ANALYTICS_SERVICE, 'analytics-service')
        ]);

        const allHealthy = healthChecks.every(check => check.healthy);
        
        return new Response(JSON.stringify({
          status: allHealthy ? 'healthy' : 'degraded',
          timestamp: new Date().toISOString(),
          services: healthChecks
        }), {
          status: allHealthy ? 200 : 503,
          headers: { 'Content-Type': 'application/json' }
        });
      } else {
        return new Response(JSON.stringify({
          error: 'Not Found',
          message: 'The requested endpoint does not exist'
        }), {
          status: 404,
          headers: { 'Content-Type': 'application/json' }
        });
      }
    } catch (error) {
      return new Response(JSON.stringify({
        error: 'Internal Server Error',
        message: error.message
      }), {
        status: 500,
        headers: { 'Content-Type': 'application/json' }
      });
    }
  }
};

async function checkServiceHealth(service, serviceName) {
  try {
    const healthRequest = new Request('http://internal/health');
    const response = await service.fetch(healthRequest);
    return {
      name: serviceName,
      healthy: response.ok,
      status: response.status
    };
  } catch (error) {
    return {
      name: serviceName,
      healthy: false,
      error: error.message
    };
  }
}


// ===== WORKER 2: user-service.js =====
// Internal worker handling user-related operations

export default {
  async fetch(request, env) {
    const url = new URL(request.url);
    const path = url.pathname;
    const method = request.method;

    if (path === '/health') {
      return new Response(JSON.stringify({ status: 'ok', service: 'user-service' }), {
        headers: { 'Content-Type': 'application/json' }
      });
    }

    try {
      if (path === '/api/users' && method === 'GET') {
        const users = await env.USER_KV.get('users', { type: 'json' }) || [];
        return new Response(JSON.stringify(users), {
          headers: { 'Content-Type': 'application/json' }
        });
      } else if (path.startsWith('/api/users/') && method === 'GET') {
        const userId = path.split('/')[3];
        const user = await env.USER_KV.get(`user:${userId}`, { type: 'json' });
        
        if (!user) {
          return new Response(JSON.stringify({ error: 'User not found' }), {
            status: 404,
            headers: { 'Content-Type': 'application/json' }
          });
        }

        await env.ANALYTICS_SERVICE.fetch(new Request('http://internal/api/analytics/track', {
          method: 'POST',
          headers: { 'Content-Type': 'application/json' },
          body: JSON.stringify({
            event: 'user_viewed',
            userId: userId,
            timestamp: Date.now()
          })
        }));

        return new Response(JSON.stringify(user), {
          headers: { 'Content-Type': 'application/json' }
        });
      } else if (path === '/api/users' && method === 'POST') {
        const userData = await request.json();
        const userId = crypto.randomUUID();
        const user = {
          id: userId,
          ...userData,
          createdAt: new Date().toISOString()
        };

        await env.USER_KV.put(`user:${userId}`, JSON.stringify(user));
        
        const users = await env.USER_KV.get('users', { type: 'json' }) || [];
        users.push({ id: userId, email: userData.email });
        await env.USER_KV.put('users', JSON.stringify(users));

        await env.ANALYTICS_SERVICE.fetch(new Request('http://internal/api/analytics/track', {
          method: 'POST',
          headers: { 'Content-Type': 'application/json' },
          body: JSON.stringify({
            event: 'user_created',
            userId: userId,
            timestamp: Date.now()
          })
        }));

        return new Response(JSON.stringify(user), {
          status: 201,
          headers: { 'Content-Type': 'application/json' }
        });
      } else {
        return new Response(JSON.stringify({ error: 'Method not allowed' }), {
          status: 405,
          headers: { 'Content-Type': 'application/json' }
        });
      }
    } catch (error) {
      return new Response(JSON.stringify({ error: error.message }), {
        status: 500,
        headers: { 'Content-Type': 'application/json' }
      });
    }
  }
};


